     public double AverageWordLength()
     {
         if (_wordLengths.Count == 0) return 0;
         int total = 0;
         for (int i = 0; i < _wordLengths.Count; i++)
             total += _wordLengths[i];
         return (double)total / _wordLengths.Count;
     }

